// Собираем все данные в структурированный контекст
// Этот шаг НЕ использует Claude — чистая обработка данных

const pg1 = $('🗄️ PG: Product & Order Metrics').first().json;
const pg2 = $('🗄️ PG: Revenue & Strategy').first().json;
const pg3 = $('🗄️ PG: Marketing & Catalog').first().json;
const ga4 = $('📈 GA4: Channels 28d').first().json;
const gsc = $('🔎 GSC: Top Pages').first().json;
const ym  = $('🛒 YM: Order Stats').first().json;

// ── Revenue calculations ──
const rev30 = parseFloat(pg2.revenue_30d) || 0;
const revYesterday = parseFloat(pg2.revenue_yesterday) || 0;
const revAvg = parseFloat(pg2.revenue_avg_day) || 0;
const revDelta = revAvg > 0 ? Math.round((revYesterday - revAvg) / revAvg * 100) : 0;
const revDayBefore = parseFloat(pg2.revenue_day_before) || 0;

// ── YM calculations ──
const ymOrdersToday = parseInt(pg2.ym_orders_today) || 0;
const ymFailedToday = parseInt(pg2.ym_failed_today) || 0;
const ymFailedPct = ymOrdersToday > 0 ? Math.round(ymFailedToday / ymOrdersToday * 100) : 0;

// ── GA4 channel parsing ──
const channels = {};
if (ga4.rows) {
  ga4.rows.forEach(row => {
    const ch = row.dimensionValues?.[0]?.value || 'unknown';
    channels[ch] = {
      sessions: parseInt(row.metricValues?.[0]?.value || 0),
      conversions: parseInt(row.metricValues?.[1]?.value || 0),
      revenue: parseFloat(row.metricValues?.[2]?.value || 0).toFixed(2)
    };
  });
}

const totalSessions = Object.values(channels).reduce((s, c) => s + c.sessions, 0);
const totalConversions = Object.values(channels).reduce((s, c) => s + c.conversions, 0);
const cr = totalSessions > 0 ? (totalConversions / totalSessions * 100).toFixed(1) : 0;

// ── GSC parsing ──
const gscRows = gsc.rows || [];
const totalClicks = gscRows.reduce((s, r) => s + (r.clicks || 0), 0);
const totalImpressions = gscRows.reduce((s, r) => s + (r.impressions || 0), 0);
const avgPos = gscRows.length > 0 ? (gscRows.reduce((s, r) => s + (r.position || 0), 0) / gscRows.length).toFixed(1) : 0;
const avgCtr = totalImpressions > 0 ? (totalClicks / totalImpressions * 100).toFixed(1) : 0;

const topPages = gscRows.slice(0, 5).map(r => ({
  url: r.keys?.[0]?.replace('https://vvv.cash', '') || r.keys?.[0],
  clicks: r.clicks,
  pos: r.position?.toFixed(1),
  ctr: (r.ctr * 100).toFixed(1) + '%'
}));

// ── Orders delta ──
const ordersToday = parseInt(pg1.orders_today) || 0;
const ordersYesterday = parseInt(pg1.orders_yesterday) || 0;
const completedYesterday = parseInt(pg1.completed_yesterday) || 0;

// ── BUILD FINAL CONTEXT ──
const context = {
  global: {
    revenue_30d: '€' + rev30,
    sessions: totalSessions,
    cr: cr,
    ym_orders_today: ymOrdersToday,
    ym_failed_pct: ymFailedPct,
    listings: parseInt(pg1.listings) || 131234,
    moderation_queue: parseInt(pg1.moderation_queue) || 10240,
  },

  seo: {
    crawled_not_indexed: 18378, // from GSC Index Coverage (requires separate API call)
    avg_position: avgPos,
    clicks_28d: totalClicks,
    ctr: avgCtr,
    sitemap_warnings: 700, // static until GSC sitemap API added
    sitemap_urls: 39220,
    oos_visible: parseInt(pg1.oos_visible) || 0,
    no_schema_count: parseInt(pg1.no_schema_count) || 0,
    thin_content_count: parseInt(pg1.thin_content_count) || 0,
    top_pages: topPages,
    delta: {
      clicks: totalClicks - 932, // vs last month baseline
      indexed: 0 // will have real data when GSC coverage API added
    }
  },

  strategy: {
    revenue_yesterday: '€' + revYesterday,
    revenue_avg: '€' + revAvg,
    revenue_delta: revDelta,
    cart_rate: totalSessions > 0 ? (ordersToday / totalSessions * 100).toFixed(1) : '?',
    purchase_rate: cr,
    stuck_fulfilled: parseInt(pg1.stuck_fulfilled) || 0,
    cancelled_today: parseInt(pg1.cancelled_today) || 0,
    refund_today: parseInt(pg2.refund_today) || 0,
    top_channels: channels,
    delta: {
      revenue: revDelta + '%',
      orders: ordersYesterday > 0 ? Math.round((ordersToday - ordersYesterday) / ordersYesterday * 100) + '%' : '?'
    }
  },

  marketing: {
    ym_impressions: parseInt(ym.result?.totals?.impressionsCount) || 0,
    ym_clicks: parseInt(ym.result?.totals?.clicksCount) || 0,
    ym_ctr: ym.result?.totals ? ((ym.result.totals.clicksCount / ym.result.totals.impressionsCount) * 100).toFixed(1) : 0,
    ym_roas: ym.result?.totals?.revenue && ym.result?.totals?.spend ? (ym.result.totals.revenue / ym.result.totals.spend).toFixed(1) : '?',
    abandoned_carts: parseInt(pg3.abandoned_carts) || 0,
    referral_cr: channels['Referral'] ? (channels['Referral'].conversions / channels['Referral'].sessions * 100).toFixed(1) : 22,
    low_ctr_sku: topPages.filter(p => parseFloat(p.ctr) < 2),
    delta: {
      ym_ctr: '?', // available after A/B test runs
      abandoned: parseInt(pg3.abandoned_carts) || 0
    }
  },

  product: {
    stuck_paid: parseInt(pg1.stuck_paid) || 0,
    stuck_inprogress: parseInt(pg1.stuck_inprogress) || 0,
    stuck_fulfilled: parseInt(pg1.stuck_fulfilled) || 0,
    mod_queue: parseInt(pg1.moderation_queue) || 0,
    mod_oldest_h: parseInt(pg1.mod_oldest_h) || 0,
    kinguin_price_changes: parseInt(pg3.kinguin_price_changes) || 0,
    kinguin_last_sync: pg3.kinguin_last_sync || 'unknown',
    urgent_products: pg3.urgent_products || [],
    delta: {
      new_orders: ordersToday,
      completed: completedYesterday
    }
  }
};

return [{ json: context }];
